window.docContents[96].resolve({"/Source-Files-and-Modules/#code-distribution":{"contents":"Lean modules are organized into packages, which are units of code distribution.\nA package may contain multiple libraries or executables.\n\nCode in a package that is intended for use by other Lean packages is organized into libraries.\nCode that is intended to be compiled and run as independent programs is organized into executables.\nPackages, libraries, and executables are described in detail in the section on Lake, the standard Lean build tool.\n\n\n","context":"Lean Reference\u0009Source Files and Modules","header":"5.7. Packages, Libraries, and Targets","id":"/Source-Files-and-Modules/#code-distribution"},"/releases/v4.28.0/#The-Lean-Language-Reference--Release-Notes--Lean-4___28___0-_LPAR_2026-02-17_RPAR_--Highlights--Library-Highlights--Ranges":{"contents":"* #11438 renames the\n  namespace Std.Range to Std.Legacy.Range. Instead of using\n  Std.Range and [a:b] notation, the new range type Std.Rco and\n  its corresponding a...b notation should be used.\n\n","context":"Lean Reference\u0009Release Notes\u0009Lean 4.28.0 (2026-02-17)\u0009Highlights\u0009Library Highlights","header":"Ranges","id":"/releases/v4.28.0/#The-Lean-Language-Reference--Release-Notes--Lean-4___28___0-_LPAR_2026-02-17_RPAR_--Highlights--Library-Highlights--Ranges"},"/releases/v4.31.0/#The-Lean-Language-Reference--Release-Notes--Lean-4___31___0-_LPAR_2026-06-13_RPAR_--Highlights--Deprecating-Modules___-Syntax___-and-Options":{"contents":"This release adds a family of tools for library authors to manage deprecations:\n\n* #13002 adds a deprecated_module command that marks the current module as deprecated; importers receive a warning suggesting replacements. A #show_deprecated_modules command lists deprecated modules in the environment.deprecated_module \"use NewModule instead\" (since := \"2026-03-30\")\n* #13108 adds a deprecated_syntax command that marks syntax kinds as deprecated, emitting a linter warning when the deprecated syntax is elaborated, including through macro expansion.* #13195 allows options to be marked deprecated, warning on set_option uses (controlled by linter.deprecated.options).\n\nA related set of new linters warns about redundant modifiers: linter.redundantVisibility for private/public that matches the default (#13132), linter.redundantExpose for no-op @[expose]/@[no_expose] (#13359), and warnings for @[simp] theorems with a variable or unrecognized head symbol (#13325).\n\n","context":"Lean Reference\u0009Release Notes\u0009Lean 4.31.0 (2026-06-13)\u0009Highlights","header":"Deprecating Modules, Syntax, and Options","id":"/releases/v4.31.0/#The-Lean-Language-Reference--Release-Notes--Lean-4___31___0-_LPAR_2026-06-13_RPAR_--Highlights--Deprecating-Modules___-Syntax___-and-Options"}});